#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        unsigned int N; if(scanf("%u",&N)!=1) break;
        int cnt=0; while(N){ N &= (N-1); cnt++; }
        printf("%d\n",cnt);
    }
    return 0;
}

